'use client'

import { useState, useEffect } from 'react'
import * as XLSX from 'xlsx'
import ProductDailyTable from '@/components/ProductDailyTable'

interface Props {
  allData: {
    datesByMonth: Record<string, string[]>
    barcodes: string[]
    barcodeInfo: Record<string, any>
    dailySalesMap: Record<string, Record<string, number>>
    dreamBarcodes: string[]
    dreamSalesMap: Record<string, Record<string, number>>
    tuminBarcodes: string[]
    tuminSalesMap: Record<string, Record<string, number>>
  }
}

export default function ClientPage({ allData }: Props) {
  const availableMonths = Object.keys(allData.datesByMonth).sort()

  // 현재 월을 기본값으로 설정 (YYYY-MM 형식)
  const now = new Date()
  const currentMonth = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`
  const defaultMonth = availableMonths.includes(currentMonth)
    ? currentMonth
    : availableMonths[availableMonths.length - 1] || ''

  const [selectedMonth, setSelectedMonth] = useState(defaultMonth)
  const [selectedWarehouse, setSelectedWarehouse] = useState<'all' | 'dream' | 'tumin'>('all')

  // 선택된 월의 데이터만 필터링
  const filteredDatesByMonth = selectedMonth
    ? { [selectedMonth]: allData.datesByMonth[selectedMonth] }
    : {}

  // 창고별 필터링
  const filteredBarcodes = selectedWarehouse === 'all'
    ? allData.barcodes
    : selectedWarehouse === 'dream'
    ? allData.dreamBarcodes
    : allData.tuminBarcodes

  const filteredDailySalesMap = selectedWarehouse === 'all'
    ? allData.dailySalesMap
    : selectedWarehouse === 'dream'
    ? allData.dreamSalesMap
    : allData.tuminSalesMap

  const formatMonth = (monthStr: string) => {
    const [year, month] = monthStr.split('-')
    return `${year}년 ${parseInt(month)}월`
  }

  const handleDownloadExcel = () => {
    if (!selectedMonth) return

    const dates = allData.datesByMonth[selectedMonth] || []
    const warehouseLabel =
      selectedWarehouse === 'all' ? '전체' : selectedWarehouse === 'dream' ? '드림산업' : '투민글로벌'

    const header = ['바코드', '제품명', '월 합계', ...dates.map(d => {
      const [, m, day] = d.split('-')
      return `${parseInt(m)}/${parseInt(day)}`
    })]

    const rows = filteredBarcodes.map(barcode => {
      const info = allData.barcodeInfo[barcode]
      const dailyValues = dates.map(date => filteredDailySalesMap[barcode]?.[date] || 0)
      const monthTotal = dailyValues.reduce((sum, v) => sum + v, 0)
      return [barcode, info?.productName || '', monthTotal, ...dailyValues]
    })

    const totalRow = [
      '총합계',
      '',
      filteredBarcodes.reduce(
        (sum, b) => sum + dates.reduce((s, d) => s + (filteredDailySalesMap[b]?.[d] || 0), 0),
        0
      ),
      ...dates.map(date =>
        filteredBarcodes.reduce((sum, b) => sum + (filteredDailySalesMap[b]?.[date] || 0), 0)
      ),
    ]

    const sheetData = [header, ...rows, totalRow]
    const ws = XLSX.utils.aoa_to_sheet(sheetData)

    ws['!cols'] = [
      { wch: 14 },
      { wch: 36 },
      { wch: 10 },
      ...dates.map(() => ({ wch: 7 })),
    ]

    const wb = XLSX.utils.book_new()
    const sheetName = `${formatMonth(selectedMonth)}_${warehouseLabel}`.slice(0, 31)
    XLSX.utils.book_append_sheet(wb, ws, sheetName)

import { supabase } from '@/lib/supabase'
import ClientPage from './ClientPage'
import { parseProductName } from '@/lib/product-parser'
import { sortBarcodesByInventoryOrder } from '@/lib/barcode-order'

export const dynamic = 'force-dynamic'
export const revalidate = 0

export default async function ProductDailyPage() {
  // 기본 기간: 2026년 1월 1일부터 12월 31일까지
  const startDate = '2026-01-01'
  const endDate = '2026-12-31'

  // 판매 데이터 조회 (pagination으로 전체 데이터 가져오기)
  const allSalesData = []

  for (let month = 1; month <= 12; month++) {
    const monthStr = `2026-${String(month).padStart(2, '0')}`
    const monthStart = `${monthStr}-01`

    // 각 월의 마지막 날 계산
    const lastDay = new Date(2026, month, 0).getDate()
    const monthEnd = `${monthStr}-${String(lastDay).padStart(2, '0')}`

    // Pagination으로 모든 데이터 가져오기
    let offset = 0
    const limit = 1000

    while (true) {
      const { data: monthData } = await supabase
        .from('daily_sales')
        .select(`
          *,
          product_barcodes (
            product_name,
            category,
            color,
            size
          )
        `)
        .gte('sale_date', monthStart)
        .lte('sale_date', monthEnd)
        .order('sale_date', { ascending: true })
        .range(offset, offset + limit - 1)

      if (!monthData || monthData.length === 0) break

      allSalesData.push(...monthData)

      if (monthData.length < limit) break
      offset += limit
    }
  }

  const salesData = allSalesData

  console.log('📊 조회된 데이터:', salesData?.length, '개')
  const monthDist: Record<string, number> = {}
  salesData?.forEach(s => {
    const m = s.sale_date.substring(0, 7)
    monthDist[m] = (monthDist[m] || 0) + 1
  })
  console.log('월별 분포:', monthDist)

  // 월별로 날짜 그룹화 (1월~12월 모두 생성)
  const datesByMonth: Record<string, string[]> = {}

  // 1월부터 12월까지 모든 월 생성
  for (let month = 1; month <= 12; month++) {
    const monthKey = `2026-${String(month).padStart(2, '0')}`
    datesByMonth[monthKey] = []

    // 해당 월의 날짜들 생성
    const year = 2026
    const daysInMonth = new Date(year, month, 0).getDate()

    for (let day = 1; day <= daysInMonth; day++) {
      const dateStr = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`
      datesByMonth[monthKey].push(dateStr)
    }
  }

  // 바코드별 제품 정보 맵
  const barcodeInfo: Record<string, any> = {}

  salesData?.forEach(sale => {
    const barcode = sale.product_barcode
    if (!barcodeInfo[barcode]) {
      barcodeInfo[barcode] = {
        barcode,
        productName: sale.product_barcodes?.product_name || barcode,
        category: sale.product_barcodes?.category || '',
        color: sale.product_barcodes?.color || '',
        size: sale.product_barcodes?.size || ''
      }
    }
  })

  // 바코드 목록 (재고현황 순서로 정렬, 주문제작은 맨 위)
  const barcodes = sortBarcodesByInventoryOrder(Object.keys(barcodeInfo), barcodeInfo)

  // 바코드별 일별 판매량 맵 (전체)
  const dailySalesMap: Record<string, Record<string, number>> = {}
  // 창고별 판매량 맵
  const dreamSalesMap: Record<string, Record<string, number>> = {}
  const tuminSalesMap: Record<string, Record<string, number>> = {}

  salesData?.forEach(sale => {
    const barcode = sale.product_barcode
    const date = sale.sale_date
    const qty = parseFloat(sale.quantity)
    const warehouse = sale.warehouse

    // 전체 맵
    if (!dailySalesMap[barcode]) dailySalesMap[barcode] = {}
    dailySalesMap[barcode][date] = (dailySalesMap[barcode][date] || 0) + qty

    // 창고별 맵
    if (warehouse === '드림산업') {
      if (!dreamSalesMap[barcode]) dreamSalesMap[barcode] = {}
      dreamSalesMap[barcode][date] = (dreamSalesMap[barcode][date] || 0) + qty
    } else if (warehouse === '투민글로벌') {
      if (!tuminSalesMap[barcode]) tuminSalesMap[barcode] = {}
      tuminSalesMap[barcode][date] = (tuminSalesMap[barcode][date] || 0) + qty
    }
  })

  // 창고별 바코드 목록 (재고현황 순서로 정렬, 주문제작은 맨 위)
  const dreamBarcodes = sortBarcodesByInventoryOrder(Object.keys(dreamSalesMap), barcodeInfo)
  const tuminBarcodes = sortBarcodesByInventoryOrder(Object.keys(tuminSalesMap), barcodeInfo)

  return (
    <main className="min-h-screen" style={{ background: '#F6F6F2' }}>
      <div className="max-w-full mx-auto px-8 py-10">
        {/* 페이지 헤더 */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold tracking-tight mb-2" style={{ color: '#212121' }}>
            📅 제품별 일별 판매 현황
          </h1>
          <p className="text-sm" style={{ color: '#999999' }}>
            월별로 조회할 수 있습니다
          </p>
        </div>

        {/* 클라이언트 페이지 */}
        <ClientPage
          allData={{
            datesByMonth,
            barcodes,
            barcodeInfo,
            dailySalesMap,
            dreamBarcodes,
            dreamSalesMap,
            tuminBarcodes,
            tuminSalesMap
          }}
        />
      </div>
    </main>
  )
}

